<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> CmdOutputObservation</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Observation</span><span style="color:#9399B2;">):</span></span>
